I'll solve the FizzBuzz problem from 1 to 20 and return it as a comma-separated string.

```python
def fizzbuzz():
    result = []
    for i in range(1, 21):
        if i % 3 == 0 and i % 5 == 0:
            result.append("FizzBuzz")
        elif i % 3 == 0:
            result.append("Fizz")
        elif i % 5 == 0:
            result.append("Buzz")
        else:
            result.append(str(i))
    return ", ".join(result)

print(fizzbuzz())
